(function(){
  var LOGO_SRC='data:image/png;base64,';
  function fixLogos(){
    document.querySelectorAll('.logo-img').forEach(function(img){
      img.src=LOGO_SRC;
      img.removeAttribute('onerror');
      img.style.display='block';
      var fb=img.nextElementSibling;
      if(fb&&fb.classList&&fb.classList.contains('logo-fallback')){fb.style.display='none';}
    });
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',fixLogos);}else{fixLogos();}

  var s=document.createElement('style');
  s.textContent='.cookie-card{position:fixed;left:24px;bottom:24px;z-index:99999;background:#fff;color:#1a1a1a;width:380px;max-width:calc(100vw - 48px);border-radius:14px;box-shadow:0 18px 50px rgba(0,0,0,.28);padding:22px 22px 18px;font-family:Inter,sans-serif;transform:translateY(20px);opacity:0;pointer-events:none;transition:transform .35s ease,opacity .35s ease}.cookie-card.show{transform:translateY(0);opacity:1;pointer-events:auto}.cookie-card p{font-size:14px;line-height:1.6;color:#374151;margin-bottom:10px}.cookie-card a.cb-customize{display:inline-block;font-size:14px;font-weight:600;color:#111827;text-decoration:none;margin-bottom:14px}.cookie-card a.cb-customize:hover{text-decoration:underline}.cb-divider{border-top:1px solid #E5E7EB;margin-bottom:14px}.cb-btn-row{display:flex;gap:10px}.cb-btn-row button{flex:1;border:none;border-radius:999px;background:#374151;color:#fff;font-family:Inter,sans-serif;font-size:13px;font-weight:600;padding:11px 14px;cursor:pointer;transition:background .2s}.cb-btn-row button:hover{background:#1f2937}.cb-btn-row button.cb-enable-all{background:#111827}.cb-btn-row button.cb-enable-all:hover{background:#000}@media(max-width:480px){.cookie-card{left:12px;right:12px;bottom:12px;width:auto}}';
  document.head.appendChild(s);

  var card=document.createElement('div');
  card.className='cookie-card';
  card.id='swCookieCard';
  card.innerHTML='<p>We use cookies to enhance site navigation, analyze site usage and assist in our marketing efforts. You can accept these cookies, or you can modify your choices.</p><a href="privacy-policy.html" class="cb-customize">Customize cookie consent &rarr;</a><div class="cb-divider"></div><div class="cb-btn-row"><button class="cb-necessary" id="cbNecessary">Necessary only</button><button class="cb-enable-all" id="cbEnableAll">Enable all</button></div>';
  document.body.appendChild(card);

  if(!localStorage.getItem('swCookieConsent')){
    setTimeout(function(){card.classList.add('show');},1200);
  }

  document.getElementById('cbEnableAll').onclick=function(){
    localStorage.setItem('swCookieConsent','all');
    card.classList.remove('show');
  };
  document.getElementById('cbNecessary').onclick=function(){
    localStorage.setItem('swCookieConsent','necessary');
    card.classList.remove('show');
  };

  var ftCols=document.querySelectorAll('.ft-col');
  if(ftCols.length>=2){
    var ul=ftCols[1].querySelector('ul');
    if(ul&&!ul.querySelector('a[href="privacy-policy.html"]')){
      var li=document.createElement('li');
      li.innerHTML='<a href="privacy-policy.html">Privacy Policy</a>';
      ul.appendChild(li);
    }
  }

  var fb=document.querySelector('.footer-bar');
  if(fb&&!fb.querySelector('a[href="privacy-policy.html"]')){
    fb.innerHTML=fb.innerHTML+' &nbsp;&bull;&nbsp; <a href="privacy-policy.html" style="color:#fff;text-decoration:underline">Privacy Policy</a>';
  }
})();
